do $$declare ws uuid;cl uuid:='10000000-0000-0000-0000-000000000001';pr uuid:='20000000-0000-0000-0000-000000000001';uid uuid;begin select id into uid from auth.users order by created_at limit 1;if uid is null then raise notice 'Crie um usuário antes de carregar o seed.';return;end if;select workspace_id into ws from public.workspace_members where user_id=uid order by created_at limit 1;insert into public.clients(id,workspace_id,name,email,whatsapp,status,created_by) values(cl,ws,'Companhia da Limpeza','contato@companhiadalimpeza.com.br','(11) 99999-0000','active',uid) on conflict(id) do nothing;insert into public.projects(id,workspace_id,client_id,name,slug,description,status,priority,agreed_value_cents,progress,last_activity_at,created_by) values(pr,ws,cl,'Companhia da Limpeza','companhia-da-limpeza','Reformulação do site e organização da infraestrutura digital.','active','high',112000,64,now()-interval '3 days',uid) on conflict(id) do nothing;
